ROOT = Path.cwd()
FILES = {'src/lib/notification-events.ts': 'import { Prisma } from "@prisma/client";\nimport { prisma } from "@/lib/prisma";\nimport {\n  sendAdminManualRefundFollowup,\n  sendNotification,\n  sendRefundApproved,\n  sendRefundRejected,\n  sendRefundRequestSubmitted,\n  sendSellerNewOrderAlert,\n  sendShippingUpdate,\n} from "@/lib/notification-service";\n\ntype AnyRecord = Record<string, any>;\n\nfunction delegateName(modelName: string) {\n  return modelName.charAt(0).toLowerCase() + modelName.slice(1);\n}\n\nfunction modelExists(modelName: string) {\n  return Boolean(\n    (Prisma as any).dmmf?.datamodel?.models?.some(\n      (model: any) => model.name === modelName\n    )\n  );\n}\n\nfunction modelFields(modelName: string) {\n  const model = (Prisma as any).dmmf?.datamodel?.models?.find(\n    (entry: any) => entry.name === modelName\n  );\n\n  return new Set<string>((model?.fields ?? []).map((field: any) => field.name));\n}\n\nfunction fieldValue<T = any>(record: AnyRecord | null | undefined, names: string[]) {\n  if (!record) return undefined;\n\n  for (const name of names) {\n    if (record[name] !== undefined && record[name] !== null && record[name] !== "") {\n      return record[name] as T;\n    }\n  }\n\n  return undefined;\n}\n\nfunction money(value: unknown) {\n  const amount =\n    typeof (value as any)?.toNumber === "function"\n      ? (value as any).toNumber()\n      : Number(value ?? 0);\n\n  return new Intl.NumberFormat("en-US", {\n    style: "currency",\n    currency: "USD",\n  }).format(Number.isFinite(amount) ? amount : 0);\n}\n\nfunction getBaseUrl() {\n  return (\n    process.env.NEXT_PUBLIC_APP_URL ??\n    process.env.NEXTAUTH_URL ??\n    "http://localhost:3000"\n  ).replace(/\\/$/, "");\n}\n\nasync function findById(modelName: string, id: string | undefined | null) {\n  if (!id || !modelExists(modelName)) return null;\n\n  const delegate = (prisma as any)[delegateName(modelName)];\n  if (!delegate?.findUnique) return null;\n\n  try {\n    return await delegate.findUnique({ where: { id } });\n  } catch {\n    return null;\n  }\n}\n\nasync function findMany(modelName: string, args: AnyRecord) {\n  if (!modelExists(modelName)) return [];\n\n  const delegate = (prisma as any)[delegateName(modelName)];\n  if (!delegate?.findMany) return [];\n\n  try {\n    return await delegate.findMany(args);\n  } catch {\n    return [];\n  }\n}\n\nasync function loadOrder(orderId: string) {\n  const order = await findById("Order", orderId);\n  if (!order) return null;\n\n  const result: AnyRecord = { ...order };\n\n  const shopId = fieldValue<string>(order, ["shopId", "storeId"]);\n  if (shopId) {\n    result.__shop = await findById("Shop", shopId);\n  }\n\n  const itemModels = ["OrderItem", "OrderLineItem", "LineItem"];\n  for (const itemModel of itemModels) {\n    const fields = modelFields(itemModel);\n    if (!fields.size) continue;\n\n    const orderLinkField = fields.has("orderId")\n      ? "orderId"\n      : fields.has("orderID")\n        ? "orderID"\n        : null;\n\n    if (!orderLinkField) continue;\n\n    const items = await findMany(itemModel, {\n      where: { [orderLinkField]: orderId },\n      take: 5,\n    });\n\n    if (items.length) {\n      result.__items = items;\n      break;\n    }\n  }\n\n  const firstItem = result.__items?.[0];\n  const productId = fieldValue<string>(firstItem, ["productId", "listingId"]);\n  if (productId) {\n    result.__product = await findById("Product", productId);\n  }\n\n  return result;\n}\n\nasync function resolveUserEmailById(id: string | undefined | null) {\n  if (!id) return undefined;\n\n  const user = await findById("User", id);\n  return fieldValue<string>(user, ["email", "emailAddress"]);\n}\n\nasync function resolveCustomerEmail(order: AnyRecord) {\n  const directEmail = fieldValue<string>(order, [\n    "customerEmail",\n    "buyerEmail",\n    "email",\n    "contactEmail",\n  ]);\n\n  if (directEmail) return directEmail;\n\n  const customerIds = [\n    fieldValue<string>(order, ["customerId"]),\n    fieldValue<string>(order, ["buyerId"]),\n    fieldValue<string>(order, ["userId"]),\n    fieldValue<string>(order, ["customerUserId"]),\n    fieldValue<string>(order, ["accountId"]),\n  ].filter(Boolean) as string[];\n\n  for (const id of customerIds) {\n    const email = await resolveUserEmailById(id);\n    if (email) return email;\n  }\n\n  return undefined;\n}\n\nasync function resolveSellerEmail(order: AnyRecord) {\n  const directOrderEmail = fieldValue<string>(order, [\n    "sellerEmail",\n    "shopEmail",\n    "merchantEmail",\n  ]);\n\n  if (directOrderEmail) return directOrderEmail;\n\n  const shop = order.__shop;\n\n  const directShopEmail = fieldValue<string>(shop, [\n    "sellerEmail",\n    "ownerEmail",\n    "email",\n    "contactEmail",\n  ]);\n\n  if (directShopEmail) return directShopEmail;\n\n  const sellerIds = [\n    fieldValue<string>(order, ["sellerId", "ownerId"]),\n    fieldValue<string>(shop, ["sellerId"]),\n    fieldValue<string>(shop, ["ownerId"]),\n    fieldValue<string>(shop, ["userId"]),\n  ].filter(Boolean) as string[];\n\n  for (const id of sellerIds) {\n    const email = await resolveUserEmailById(id);\n    if (email) return email;\n  }\n\n  return undefined;\n}\n\nfunction getOrderNumber(order: AnyRecord) {\n  return (\n    fieldValue<string>(order, ["orderNumber", "number", "code", "reference"]) ??\n    order.id\n  );\n}\n\nfunction getOrderTotal(order: AnyRecord) {\n  return fieldValue(order, ["total", "totalAmount", "amount", "subtotal"]) ?? 0;\n}\n\nfunction getShopName(order: AnyRecord) {\n  return (\n    fieldValue<string>(order.__shop, ["shopName", "name", "title"]) ??\n    fieldValue<string>(order, ["shopName", "sellerName"]) ??\n    "Betsy Home"\n  );\n}\n\nfunction getProductTitle(order: AnyRecord) {\n  const firstItem = order.__items?.[0];\n\n  return (\n    fieldValue<string>(order.__product, ["title", "name"]) ??\n    fieldValue<string>(firstItem, ["productTitle", "title", "name"]) ??\n    "your item"\n  );\n}\n\nasync function orderPayload(order: AnyRecord) {\n  const orderNumber = getOrderNumber(order);\n  const baseUrl = getBaseUrl();\n  const customerEmail = await resolveCustomerEmail(order);\n  const sellerEmail = await resolveSellerEmail(order);\n\n  return {\n    orderNumber,\n    orderTotal: money(getOrderTotal(order)),\n    shopName: getShopName(order),\n    customerEmail,\n    sellerEmail,\n    productTitle: getProductTitle(order),\n    trackingCarrier: fieldValue<string>(order, [\n      "trackingCarrier",\n      "carrier",\n      "shippingCarrier",\n    ]),\n    trackingNumber: fieldValue<string>(order, [\n      "trackingNumber",\n      "trackingCode",\n      "shippingTrackingNumber",\n    ]),\n    trackingUrl: fieldValue<string>(order, [\n      "trackingUrl",\n      "trackingURL",\n      "shippingTrackingUrl",\n    ]),\n    refundReason: fieldValue<string>(order, ["refundReason", "cancellationReason"]),\n    resolutionNote: fieldValue<string>(order, [\n      "refundResolutionNote",\n      "resolutionNote",\n      "refundNote",\n    ]),\n    adminReference: fieldValue<string>(order, [\n      "stripeRefundId",\n      "manualRefundReference",\n      "refundReference",\n    ]),\n    actionUrl: `${baseUrl}/account/orders/${order.id}`,\n  };\n}\n\nasync function adminEmail() {\n  return process.env.ADMIN_EMAIL ?? process.env.SUPPORT_EMAIL ?? "admin@betsyhome.test";\n}\n\nexport async function notifyOrderCreated(orderId: string) {\n  const order = await loadOrder(orderId);\n\n  if (!order) {\n    return { ok: false, reason: "order_not_found", orderId };\n  }\n\n  const payload = await orderPayload(order);\n  const results = [];\n  const skipped = [];\n\n  if (payload.customerEmail) {\n    results.push(\n      await sendNotification({\n        kind: "order_confirmation",\n        to: payload.customerEmail,\n        payload,\n      })\n    );\n  } else {\n    skipped.push("customer_email_not_found");\n  }\n\n  if (payload.sellerEmail) {\n    results.push(await sendSellerNewOrderAlert(payload.sellerEmail, payload));\n  } else {\n    skipped.push("seller_email_not_found");\n  }\n\n  return {\n    ok: true,\n    event: "order_created",\n    orderId,\n    notifications: results.length,\n    skipped,\n    resolved: {\n      customerEmail: payload.customerEmail ?? null,\n      sellerEmail: payload.sellerEmail ?? null,\n      shopName: payload.shopName,\n      orderNumber: payload.orderNumber,\n    },\n    results,\n  };\n}\n\nexport async function notifyShippingUpdated(orderId: string) {\n  const order = await loadOrder(orderId);\n\n  if (!order) {\n    return { ok: false, reason: "order_not_found", orderId };\n  }\n\n  const payload = await orderPayload(order);\n  const to = payload.customerEmail;\n\n  if (!to) {\n    return {\n      ok: false,\n      reason: "customer_email_not_found",\n      orderId,\n      resolved: {\n        sellerEmail: payload.sellerEmail ?? null,\n        shopName: payload.shopName,\n        orderNumber: payload.orderNumber,\n      },\n    };\n  }\n\n  const result = await sendShippingUpdate(to, payload);\n\n  return {\n    ok: true,\n    event: "shipping_updated",\n    orderId,\n    notifications: 1,\n    resolved: {\n      customerEmail: to,\n      shopName: payload.shopName,\n      orderNumber: payload.orderNumber,\n    },\n    result,\n  };\n}\n\nexport async function notifyRefundRequested(orderId: string) {\n  const order = await loadOrder(orderId);\n\n  if (!order) {\n    return { ok: false, reason: "order_not_found", orderId };\n  }\n\n  const payload = await orderPayload(order);\n  const results = [];\n  const skipped = [];\n\n  if (payload.sellerEmail) {\n    results.push(await sendRefundRequestSubmitted(payload.sellerEmail, payload));\n  } else {\n    skipped.push("seller_email_not_found");\n  }\n\n  results.push(\n    await sendRefundRequestSubmitted(await adminEmail(), {\n      ...payload,\n      actionUrl: `${getBaseUrl()}/admin/refunds`,\n    })\n  );\n\n  return {\n    ok: true,\n    event: "refund_requested",\n    orderId,\n    notifications: results.length,\n    skipped,\n    resolved: {\n      customerEmail: payload.customerEmail ?? null,\n      sellerEmail: payload.sellerEmail ?? null,\n      shopName: payload.shopName,\n      orderNumber: payload.orderNumber,\n    },\n    results,\n  };\n}\n\nexport async function notifyRefundResolved(orderId: string) {\n  const order = await loadOrder(orderId);\n\n  if (!order) {\n    return { ok: false, reason: "order_not_found", orderId };\n  }\n\n  const payload = await orderPayload(order);\n  const to = payload.customerEmail;\n\n  if (!to) {\n    return {\n      ok: false,\n      reason: "customer_email_not_found",\n      orderId,\n      resolved: {\n        sellerEmail: payload.sellerEmail ?? null,\n        shopName: payload.shopName,\n        orderNumber: payload.orderNumber,\n      },\n    };\n  }\n\n  const status = String(\n    fieldValue(order, ["refundRequestStatus", "refundStatus"]) ?? ""\n  ).toUpperCase();\n\n  const result =\n    status === "REJECTED" || status === "DECLINED"\n      ? await sendRefundRejected(to, payload)\n      : await sendRefundApproved(to, payload);\n\n  return {\n    ok: true,\n    event: "refund_resolved",\n    orderId,\n    notifications: 1,\n    resolved: {\n      customerEmail: to,\n      shopName: payload.shopName,\n      orderNumber: payload.orderNumber,\n      refundStatus: status || null,\n    },\n    result,\n  };\n}\n\nexport async function notifyManualRefundFollowup(orderId: string) {\n  const order = await loadOrder(orderId);\n\n  if (!order) {\n    return { ok: false, reason: "order_not_found", orderId };\n  }\n\n  const payload = {\n    ...(await orderPayload(order)),\n    actionUrl: `${getBaseUrl()}/admin/refunds`,\n  };\n\n  const result = await sendAdminManualRefundFollowup(await adminEmail(), payload);\n\n  return {\n    ok: true,\n    event: "manual_refund_followup",\n    orderId,\n    notifications: 1,\n    resolved: {\n      adminEmail: await adminEmail(),\n      shopName: payload.shopName,\n      orderNumber: payload.orderNumber,\n    },\n    result,\n  };\n}\n\nexport const notificationEventHandlers = {\n  order_created: notifyOrderCreated,\n  shipping_updated: notifyShippingUpdated,\n  refund_requested: notifyRefundRequested,\n  refund_resolved: notifyRefundResolved,\n  manual_refund_followup: notifyManualRefundFollowup,\n};\n', 'docs/notification-email-resolver-hardening.md': '# Notification email resolver hardening\n\nThis patch makes `src/lib/notification-events.ts` resolve customer and seller emails from scalar IDs instead of relying only on Prisma relation includes.\n\nIt checks fields like:\n\n- `customerEmail`\n- `buyerEmail`\n- `customerId`\n- `buyerId`\n- `userId`\n- `shopId`\n- `shop.sellerId`\n- `shop.ownerId`\n- `shop.userId`\n- `shop.email`\n- `shop.sellerEmail`\n\nThen it returns a `resolved` object in event endpoint responses so you can see which emails were found.\n\n## Test\n\n```bash\ncurl -X POST http://localhost:3000/api/notifications/events/order-created -H "Content-Type: application/json" -d \'{"orderId":"cmq1ziigx00037k5k07m50nhq"}\'\n```\n\nExpected response should include `notifications: 1` or `notifications: 2`, depending on whether both customer and seller email were resolved.\n'}

def ensure_parent(path: Path):
    path.parent.mkdir(parents=True, exist_ok=True)

def write_file(path_str: str, content: str):
    path = ROOT / path_str
    ensure_parent(path)
    path.write_text(content, encoding="utf-8")
    print(f"wrote {path_str}")

for path_str, content in FILES.items():
    write_file(path_str, content)

print("\nDone.")
